const body = items[0].json.body || items[0].json;
const pregunta = (body.pregunta || '').toString().trim();
if (!pregunta) throw new Error('Falta `pregunta` en el body');
const usePubmed = body.usePubmed !== false; // default true
const payload = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1024,
  system: 'Eres un asistente de síntesis de evidencia para epidemiólogos. Busca en PubMed/NCBI y fuentes revisadas por pares. Responde SIEMPRE en español, conciso y estructurado: (1) Hallazgo principal, (2) Calidad/diseño de la evidencia, (3) Limitaciones, (4) Fuentes con autor/año/PMID o DOI cuando existan. No inventes citas; si no hay evidencia clara, dilo.',
  messages: [{ role: 'user', content: pregunta }],
  tools: [{ type: 'web_search_20250305', name: 'web_search' }]
};
if (usePubmed) payload.mcp_servers = [{ type: 'url', url: 'https://pubmed.mcp.claude.com/mcp', name: 'pubmed' }];
return [{ json: { payload, pregunta, usePubmed } }];

const r = items[0].json;
if (r.error) return [{ json: { text: '', error: r.error.message || 'error' } }];
const content = r.content || [];
const text = content.filter(b => b.type === 'text').map(b => b.text).join('\n').trim();
// Extraer fuentes desde resultados MCP/web_search cuando estén disponibles
const sources = [];
content.forEach(b => {
  if (b.type === 'mcp_tool_result' && Array.isArray(b.content)) {
    b.content.forEach(c => {
      if (c.type === 'text' && /PMID|pubmed\.ncbi/.test(c.text || '')) {
        const m = (c.text || '').match(/PMID[:\s]*(\d+)/i);
        sources.push({ pmid: m ? m[1] : null, text: c.text.slice(0, 240) });
      }
    });
  }
});
return [{ json: { text, sources } }];
